// ═══════════════════════════════════════
// HAPPY PATH — parsear respuesta del LLM
// ═══════════════════════════════════════

const aiData = $input.first().json;
const inputData = $('⏱️ Start timer').first().json;

const content = aiData?.choices?.[0]?.message?.content || '';

function tryParse(s) {
  try { return JSON.parse(s); } catch (e) {}
  const cleaned = s.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '').trim();
  try { return JSON.parse(cleaned); } catch (e) {}
  return { urgency: 'P3', reasoning: content.slice(0, 100) };
}

const parsed = tryParse(content);

return [{
  json: {
    ...inputData,
    priority: parsed.urgency,
    reasoning: parsed.reasoning,
    fallbackUsed: false,
    tokensUsed: aiData?.usage?.total_tokens || 0
  }
}];

// ═══════════════════════════════════════
// FALLBACK — clasificación por reglas
// ═══════════════════════════════════════
// Se activa cuando el LLM falla (timeout, 5xx, sin content).
// Produce el MISMO shape que la rama IA para que el flujo siga igual.

const inputData = $('⏱️ Start timer').first().json;
const vitals = inputData.vitals || {};

let priority = 'P3';
let reasoning = 'Clasificación por reglas (IA no disponible)';

if (vitals.spo2 != null && vitals.spo2 < 92) {
  priority = 'P1';
  reasoning = 'FALLBACK: SpO2 crítico (<92).';
} else if (vitals.hr != null && vitals.hr > 110) {
  priority = 'P1';
  reasoning = 'FALLBACK: taquicardia severa (HR >110).';
} else if (inputData.age && inputData.age > 65) {
  priority = 'P2';
  reasoning = 'FALLBACK: adulto mayor con síntomas, evaluación urgente.';
}

return [{
  json: {
    ...inputData,
    priority,
    reasoning,
    fallbackUsed: true,
    tokensUsed: 0
  }
}];

// ═══════════════════════════════════════
// LOG ESTRUCTURADO + MÉTRICAS
// ═══════════════════════════════════════
// Convierte el estado del flujo en un JSON
// listo para enviar a un logger (Loki, Datadog, etc).

const d = $input.first().json;
const now = Date.now();
const latencyMs = d.startedAtMs ? (now - d.startedAtMs) : null;

const log = {
  event: 'triage_completed',
  ts: new Date(now).toISOString(),
  priority: d.priority,
  fallbackUsed: d.fallbackUsed,
  tokensUsed: d.tokensUsed,
  latencyMs
};

return [{
  json: {
    triage: {
      priority: d.priority,
      reasoning: d.reasoning
    },
    log
  }
}];
